 static void sdp_parse_line(AVFormatContext *s, SDPParseState *s1,
                            int letter, const char *buf)
 {
     RTSPState *rt = s->priv_data;
     char buf1[64], st_type[64];
     const char *p;
     enum AVMediaType codec_type;
     int payload_type;
     AVStream *st;
     RTSPStream *rtsp_st;
     RTSPSource *rtsp_src;
     struct sockaddr_storage sdp_ip;
     int ttl;

     av_log(s, AV_LOG_TRACE, "sdp: %c='%s'\n", letter, buf);

     p = buf;
     if (s1->skip_media && letter != 'm')
         return;
     switch (letter) {
     case 'c':
         get_word(buf1, sizeof(buf1), &p);
         if (strcmp(buf1, "IN") != 0)
             return;
         get_word(buf1, sizeof(buf1), &p);
         if (strcmp(buf1, "IP4") && strcmp(buf1, "IP6"))
             return;
         get_word_sep(buf1, sizeof(buf1), "/", &p);
         if (get_sockaddr(s, buf1, &sdp_ip))
             return;
         ttl = 16;
         if (*p == '/') {
             p++;
             get_word_sep(buf1, sizeof(buf1), "/", &p);
             ttl = atoi(buf1);
         }
         if (s->nb_streams == 0) {
             s1->default_ip = sdp_ip;
             s1->default_ttl = ttl;
         } else {
             rtsp_st = rt->rtsp_streams[rt->nb_rtsp_streams - 1];
             rtsp_st->sdp_ip = sdp_ip;
             rtsp_st->sdp_ttl = ttl;
         }
         break;
     case 's':
         av_dict_set(&s->metadata, "title", p, 0);
         break;
     case 'i':
         if (s->nb_streams == 0) {
             av_dict_set(&s->metadata, "comment", p, 0);
             break;
         }
         break;
     case 'm':
         /* new stream */
         s1->skip_media  = 0;
         s1->seen_fmtp   = 0;
         s1->seen_rtpmap = 0;
         codec_type = AVMEDIA_TYPE_UNKNOWN;
         get_word(st_type, sizeof(st_type), &p);
         if (!strcmp(st_type, "audio")) {
             codec_type = AVMEDIA_TYPE_AUDIO;
         } else if (!strcmp(st_type, "video")) {
             codec_type = AVMEDIA_TYPE_VIDEO;
         } else if (!strcmp(st_type, "application")) {
             codec_type = AVMEDIA_TYPE_DATA;
         } else if (!strcmp(st_type, "text")) {
             codec_type = AVMEDIA_TYPE_SUBTITLE;
         }
         if (codec_type == AVMEDIA_TYPE_UNKNOWN ||
             !(rt->media_type_mask & (1 << codec_type)) ||
             rt->nb_rtsp_streams >= s->max_streams
         ) {
             s1->skip_media = 1;

